        .ty = @enumFromInt(0),
        .source_region = base.Region.zero(),
        .data = switch (kind) {
            .local => .{ .lookup_local = .{
                .pattern = @enumFromInt(0),
                .resolved = @enumFromInt(0),
            } },
            .external => .{ .lookup_external = @enumFromInt(0) },
        },
    });
    try artifact.checked_bodies.bodies.append(gpa, .{
        .id = @enumFromInt(0),
        .root_expr = @enumFromInt(0),
